def compare_numbers(a, b):
    if a > b:
        print('First number is greater')
    elif a < b:
        print('First number is less')
    else:
        print('Both numbers are equal')

# Example usage
compare_numbers(5, 3)

def check_truthiness(value):
    if value:
        print('Value is truthy')
    else:
        print('Value is falsy')

# Example usage
check_truthiness(0)
check_truthiness('Hello')
